import{_ as e,o as i,c as n,ag as t}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias Rust | Dotfiles (ID)","titleTemplate":":title","description":"Alias Rust adalah koleksi alias yang memungkinkan Anda berinteraksi dengan perintah `rustup` dan `cargo`. Dirancang untuk digunakan dengan toolchain manager `rustup` dan package manager `cargo`.","frontmatter":{"title":"Alias Rust | Dotfiles","description":"Alias Rust adalah koleksi alias yang memungkinkan Anda berinteraksi dengan perintah `rustup` dan `cargo`. Dirancang untuk digunakan dengan toolchain manager `rustup` dan package manager `cargo`.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Rust preview","canonical":"/id/aliases/rust/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Rust","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Rust - Dotfiles (ID)","permalink":"/id/aliases/rust/","meta":[{"name":"keywords","content":"alias, cargo, rust, rustup, linux, macos, shell, terminal, windows"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Alias Rust adalah koleksi alias untuk berinteraksi dengan perintah `rustup` dan `cargo`."},{"name":"twitter:title","content":"Alias Rust - Dotfiles (ID)"},{"name":"og:title","content":"Alias Rust - Dotfiles (ID)"},{"name":"og:description","content":"Alias Rust adalah koleksi alias untuk berinteraksi dengan perintah `rustup` dan `cargo`."},{"name":"og:image:alt","content":"Dotfiles - Dirancang sederhana untuk menyesuaikan kehidupan shell Anda"},{"name":"og:locale","content":"id_ID"}]},"headers":[],"relativePath":"id/aliases/rust/index.md","filePath":"id/aliases/rust/index.md","lastUpdated":1773010926000}'),l={name:"id/aliases/rust/index.md"};function d(o,a,s,r,c,u){return i(),n("div",null,[...a[0]||(a[0]=[t('<h1 id="alias-rust" tabindex="-1">Alias Rust <a class="header-anchor" href="#alias-rust" aria-label="Permalink to &quot;Alias Rust&quot;">​</a></h1><p>Kelola alias Rust. Bagian dari konfigurasi <strong>Universal Dotfiles</strong>.</p><h2 id="ikhtisar" tabindex="-1">Ikhtisar <a class="header-anchor" href="#ikhtisar" aria-label="Permalink to &quot;Ikhtisar&quot;">​</a></h2><p>Alias ini didefinisikan di <code>rust.aliases.sh</code> dan dimuat secara otomatis oleh <code>chezmoi</code>.</p><h2 id="alias" tabindex="-1">Alias <a class="header-anchor" href="#alias" aria-label="Permalink to &quot;Alias&quot;">​</a></h2><p>Kode ini menyediakan set alias komprehensif untuk pengembangan Rust menggunakan perintah <code>cargo</code> dan <code>rustup</code>.</p><h3 id="perintah-dasar" tabindex="-1">Perintah Dasar <a class="header-anchor" href="#perintah-dasar" aria-label="Permalink to &quot;Perintah Dasar&quot;">​</a></h3><ul><li><code>cg</code> - Pintasan Cargo</li><li><code>cgn</code> - Buat proyek binary baru</li><li><code>cgni</code> - Buat proyek library baru</li><li><code>cginit</code> - Inisialisasi proyek di direktori saat ini</li></ul><h3 id="build-dan-run" tabindex="-1">Build dan Run <a class="header-anchor" href="#build-dan-run" aria-label="Permalink to &quot;Build dan Run&quot;">​</a></h3><ul><li><code>cgb</code> - Debug build</li><li><code>cgbr</code> - Release build</li><li><code>cgr</code> - Debug run</li><li><code>cgrr</code> - Release run</li><li><code>cgw</code> - Watch dan rebuild</li></ul><h3 id="testing-dan-benchmark" tabindex="-1">Testing dan Benchmark <a class="header-anchor" href="#testing-dan-benchmark" aria-label="Permalink to &quot;Testing dan Benchmark&quot;">​</a></h3><ul><li><code>cgt</code> - Jalankan test</li><li><code>cgtr</code> - Jalankan test dalam mode release</li><li><code>cgbh</code> - Jalankan benchmark</li><li><code>cgta</code> - Test semua target</li><li><code>cgtt</code> - Test single-threaded</li></ul><h3 id="kualitas-kode" tabindex="-1">Kualitas Kode <a class="header-anchor" href="#kualitas-kode" aria-label="Permalink to &quot;Kualitas Kode&quot;">​</a></h3><ul><li><code>cgc</code> - Periksa kompilasi</li><li><code>cgcl</code> - Bersihkan artifact build</li><li><code>cgcy</code> - Jalankan linter Clippy</li><li><code>cgf</code> - Format kode</li><li><code>cgfa</code> - Format semua kode</li><li><code>cgfx</code> - Auto-fix masalah kode</li><li><code>cgaud</code> - Periksa kerentanan keamanan</li></ul><h3 id="dokumentasi" tabindex="-1">Dokumentasi <a class="header-anchor" href="#dokumentasi" aria-label="Permalink to &quot;Dokumentasi&quot;">​</a></h3><ul><li><code>cgd</code> - Build dan buka dokumentasi</li><li><code>cgdr</code> - Build dokumentasi release</li><li><code>cgdo</code> - Dokumentasi item private</li></ul><h3 id="dependensi" tabindex="-1">Dependensi <a class="header-anchor" href="#dependensi" aria-label="Permalink to &quot;Dependensi&quot;">​</a></h3><ul><li><code>cga</code> - Tambah dependensi</li><li><code>cgad</code> - Tambah dependensi development</li><li><code>cgu</code> - Update dependensi</li><li><code>cgo</code> - Periksa dependensi outdated</li><li><code>cgtree</code> - Tampilkan tree dependensi</li></ul><h3 id="update-dan-install" tabindex="-1">Update dan Install <a class="header-anchor" href="#update-dan-install" aria-label="Permalink to &quot;Update dan Install&quot;">​</a></h3><ul><li><code>ru</code> - Update semua toolchain</li><li><code>rus</code> - Update toolchain stable</li><li><code>run</code> - Update toolchain nightly</li><li><code>rti</code> - Install toolchain tertentu</li></ul><h3 id="manajemen-toolchain" tabindex="-1">Manajemen Toolchain <a class="header-anchor" href="#manajemen-toolchain" aria-label="Permalink to &quot;Manajemen Toolchain&quot;">​</a></h3><ul><li><code>rtl</code> - List toolchain terinstal</li><li><code>rtu</code> - Uninstall toolchain</li><li><code>rde</code> - Atur toolchain default</li></ul>',22)])])}const g=e(l,[["render",d]]);export{m as __pageData,g as default};
